import React from "react";

export default function FriendsList({ friends, onSelectFriend }) {
  return (
    <div style={{ padding: "20px" }}>
      <h2>Chats</h2>
      {friends.map(friend => (
        <div
          key={friend.userId}
          onClick={() => onSelectFriend(friend)}
          style={{
            padding: "15px",
            borderBottom: "1px solid #ddd",
            cursor: "pointer",
            background: "#fff"
          }}
        >
          {friend.userId}
        </div>
      ))}
    </div>
  );
}
